import type { UploadProgressEvent, UploadRequestError, UploadRequestOption } from '../interface';

const getError = (option: UploadRequestOption, xhr: XMLHttpRequest) => {
  const msg = `cannot ${option.method} ${option.action} ${xhr.status}'`;
  const err = new Error(msg) as UploadRequestError;
  err.status = xhr.status;
  err.method = option.method;
  err.url = option.action;
  return err;
};

const getBody = (xhr: XMLHttpRequest) => {
  const text = xhr.responseText || xhr.response;
  if (!text) {
    return text;
  }

  try {
    return JSON.parse(text);
  } catch (e) {
    return text;
  }
};

export const upload = (option: UploadRequestOption) => {
  const xhr = new XMLHttpRequest();

  if (option.onProgress && xhr.upload) {
    // 这里 xhr.upload.onprogress 的类型应该改为 (e: UploadProgressEvent) => void
    // 但是不知道为啥死活改不对
    (xhr.upload.onprogress as unknown) = function progress(e: UploadProgressEvent) {
      if (e.total > 0) {
        e.percent = (e.loaded / e.total) * 100;
      }
      option.onProgress?.(e);
    };
  }

  const formData = new FormData();

  if (option.data) {
    Object.entries(option.data).forEach(([key, value]) => {
      if (Array.isArray(value)) {
        value.forEach(item => {
          formData.append(`${key}[]`, item);
        });
        return;
      }

      formData.append(key, value);
    });
  }

  if (option.file instanceof Blob) {
    formData.append(option.filename || '', option.file, (option.file as any).name);
  } else {
    formData.append(option.filename || '', option.file);
  }

  xhr.onerror = function error(e) {
    option.onError?.(e);
  };

  xhr.onload = function onload() {
    // allow success when 2xx status
    // eslint-disable-next-line @typescript-eslint/no-magic-numbers
    if (xhr.status < 200 || xhr.status >= 300) {
      return option.onError?.(getError(option, xhr), getBody(xhr));
    }

    return option.onSuccess?.(getBody(xhr), xhr);
  };

  xhr.open(option.method, option.action, true);

  // Has to be after `.open()`. See https://github.com/enyo/dropzone/issues/179
  if (option.withCredentials && 'withCredentials' in xhr) {
    xhr.withCredentials = true;
  }

  const headers = option.headers || {};

  // when set headers['X-Requested-With'] = null , can close default XHR header
  if (headers['X-Requested-With'] !== null) {
    xhr.setRequestHeader('X-Requested-With', 'XMLHttpRequest');
  }

  Object.keys(headers).forEach(h => {
    if (headers[h] !== null) {
      xhr.setRequestHeader(h, headers[h]);
    }
  });

  xhr.send(formData);

  return {
    abort() {
      xhr.abort();
    },
  };
};

export default upload;
